  ('dietitian-moex-04695', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '病人的血液生化數值例如：空腹血糖、膽固醇等，在SOAP紀錄法中應在下列那個部分？', '["subjective", "objective", "assessment", "plan"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04696', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '成人尿液分析中出現下列何者可視為正常生理現象？', '["葡萄糖", "膽紅素", "酮體", "蛋白質"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04697', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '病人裝置Gastrojejunaldualtubes的目的是：', '["提供更大的灌食量，幫助病人更容易達到熱量需求", "通常一條管路灌藥，一條管路灌食，避免飲食與藥物產生交互作用", "通常一條管路引流，一條管路灌食，有助於術後早期腸道營養", "通常一條管路灌食，一條管路灌水，用於需要大量水分補充的病人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04698', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '病人在決定利用管灌營養（tubefeeding）支持時，對於其插管方式需考量的因素，下列何者 錯誤？', '["需使用管灌營養支持的時間長短", "病人是否有吸入性嗆傷或肺炎的危險", "病人是否呈現昏迷的狀態", "未來是否有進行其他手術的計畫"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04699', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列對全靜脈營養（totalparenteralnutrition,TPN）營養配方的敘述何者錯誤？', '["配方中胺基酸的組成包含所有必需胺基酸，而在非必需胺基酸方面牛磺酸（taurine）通常 可添加在給予嬰兒的配方中，故牛磺酸被認為是條件性必需（conditionallyessential）胺基酸", "配方中的脂肪乳劑除可以供應熱量外亦可供應必需脂肪酸（essentialfattyacid），為了避免 必需脂肪酸缺乏，亞麻油酸（linoleic acid）提供之熱量約需占總熱量之0.25%，而α-次亞 麻油酸（α-linolenic acid）提供之熱量則約占總熱量之2～4%", "如果全靜脈營養需要使用超過 6 個月以上，則需追蹤血液中的錳（manganese）及鉻 （chromium）", "鐵因為與脂肪乳劑不相溶且可能會促進微生物的生長，故一般來說不會添加在全靜脈之營 養輸液中"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04700', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '王先生為中風病人並接受常規復健治療，本次因感冒發燒入院，有吸入性肺炎、高血壓的病 史，本次入院後醫師放置鼻胃管以灌食幫浦（feedingpump）連續灌食作為營養支持路徑，飲 食處方為1,800大卡高蛋白飲食。除肺炎的控制外，王先生每天早上10時至11時須至復健 部進行治療，其餘時間仍維持連續灌食。經營養師評估後，較適合建議下列何種灌食方式？', '["bolusfeeding", "intermittentfeeding", "cyclicfeeding", "gravityfeeding"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04701', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關脂肪細胞（adipocyte）的敘述，下列何者正確？', '["僅有肥胖兒童在進入青春期時，脂肪細胞數量會增加", "正常成長過程，體脂肪在6歲時達到最大比例", "正確的減重方式，可以使脂肪細胞體積和數量降低", "半揮發性有機化合物（semivolatileorganiccompounds）會儲存在脂肪細胞中"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04702', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關神經性厭食症（anorexianervosa）病人的營養素需求，下列何者正確？', '["低體重病人常有維生素B 缺乏，再餵食（refeeding）階段需額外補充 1", "低體重病人血清25-hydroxyvitaminD濃度通常過高", "因高胡蘿蔔素血症（hypercarotenemia），需限制病人類胡蘿蔔素的攝取", "限鈉飲食（2公克／天）對病人的水分滯留沒有幫助"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04703', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '體重控制過程中常採用行為療法來輔助減重，下列敘述何者不屬於刺激控制療法（stimulus control）？', '["介入個案進食時間，如增加咀嚼次數或增加放下餐具的次數，以延長用餐時間", "請個案詳細記錄每日進食量、時間、地點和情緒", "建議個案只能在特定地點進食，並採用特定餐具", "要求個案不可將進食與其它活動同時進行，如看電視或講電話"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
